module.render:
const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const op = String(args.op || 'intersect');
const color = args.color || 'var(--accent-color)';
const width = (args.width || '').trim();
const intensityRaw = (args.intensity === undefined || args.intensity === '') ? 40 : parseFloat(args.intensity);
const intensity = Number.isFinite(intensityRaw) ? Math.max(0, Math.min(100, intensityRaw)) : 40;
const showU = String(args.showu === undefined ? 'true' : args.showu) !== 'false';
const showFrame = String(args.frame === undefined ? 'true' : args.frame) !== 'false';
const uid = 'so' + op.replace(/[^a-z]/g, '') + String(args.a || 'A').length + String(args.b || 'B').length;
const A = { x: 62, y: 50, r: 34 }, B = { x: 98, y: 50, r: 34 };
const circ = (c, cls) => `<circle cx="${c.x}" cy="${c.y}" r="${c.r}" class="${cls}"/>`;
const defs = `<defs>` +
  `<clipPath id="${uid}-ca"><circle cx="${A.x}" cy="${A.y}" r="${A.r}"/></clipPath>` +
  `<mask id="${uid}-ma"><rect x="0" y="0" width="160" height="100" fill="#fff"/><circle cx="${A.x}" cy="${A.y}" r="${A.r}" fill="#000"/></mask>` +
  `<mask id="${uid}-mb"><rect x="0" y="0" width="160" height="100" fill="#fff"/><circle cx="${B.x}" cy="${B.y}" r="${B.r}" fill="#000"/></mask>` +
  `<mask id="${uid}-mab"><rect x="0" y="0" width="160" height="100" fill="#fff"/><circle cx="${A.x}" cy="${A.y}" r="${A.r}" fill="#000"/><circle cx="${B.x}" cy="${B.y}" r="${B.r}" fill="#000"/></mask>` +
  `</defs>`;
let fill = '';
const fA = circ(A, 'mdp-so-fill'), fB = circ(B, 'mdp-so-fill');
if (op === 'union') fill = fA + fB;
else if (op === 'intersect') fill = `<g clip-path="url(#${uid}-ca)">${fB}</g>`;
else if (op === 'a-only') fill = `<g mask="url(#${uid}-mb)">${fA}</g>`;
else if (op === 'b-only') fill = `<g mask="url(#${uid}-ma)">${fB}</g>`;
else if (op === 'xor') fill = `<g mask="url(#${uid}-mb)">${fA}</g><g mask="url(#${uid}-ma)">${fB}</g>`;
else if (op === 'complement') fill = `<rect x="2" y="2" width="156" height="96" rx="6" class="mdp-so-fill" mask="url(#${uid}-mab)"/>`;
const frameRect = showFrame ? `<rect x="2" y="2" width="156" height="96" rx="6" class="mdp-so-frame"/>` : '';
const uText = showU ? `<text x="8" y="13" class="mdp-so-u">U</text>` : '';
const frame = frameRect + uText +
  circ(A, 'mdp-so-circle') + circ(B, 'mdp-so-circle') +
  `<text x="${A.x - A.r + 6}" y="${A.y - A.r + 2}" class="mdp-so-lbl">${esc(args.a || 'A')}</text>` +
  `<text x="${B.x + B.r - 6}" y="${B.y - B.r + 2}" class="mdp-so-lbl" text-anchor="end">${esc(args.b || 'B')}</text>`;
let styleVars = `--so-c:${color};--so-fill:${intensity}%;`;
if (width) styleVars += `--so-w:${width};`;
let html = `\n\n<div class="mdp-mod-setops" style="${styleVars}"><svg viewBox="0 0 160 100" preserveAspectRatio="xMidYMid meet">${defs}${fill}${frame}</svg>`;
if (args.formula) html += `<div class="mdp-so-formula">\n\n${args.formula}\n\n</div>`;
html += `</div>\n\n`;
return html;
